/**
 * Post-build script that fixes the wrangler.json generated by @astrojs/cloudflare v13.
 *
 * The adapter generates bindings (KV SESSION, IMAGES, ASSETS) and fields that
 * Cloudflare Pages V3 build system rejects:
 * - "ASSETS" is a reserved name in Pages
 * - "kv_namespaces" needs real binding IDs
 * - "images" binding not supported in Pages
 * - Various unsupported fields in triggers, dev, etc.
 *
 * This script strips problematic fields so Pages V3 can read the config.
 */
import { readFileSync, writeFileSync } from 'fs';

const configPath = 'dist/server/wrangler.json';

try {
  const raw = readFileSync(configPath, 'utf-8');
  const config = JSON.parse(raw);

  // Keep only the fields Pages V3 understands
  // CRITICAL: pages_build_output_dir must be present for Pages V3 to recognize this as valid
  const clean = {
    name: config.name,
    pages_build_output_dir: ".",
    main: config.main,
    compatibility_date: config.compatibility_date,
    compatibility_flags: config.compatibility_flags,
    assets: config.assets ? { directory: config.assets.directory } : undefined,
    rules: config.rules,
    no_bundle: config.no_bundle,
    vars: config.vars,
  };

  // Remove undefined keys
  Object.keys(clean).forEach(k => clean[k] === undefined && delete clean[k]);

  writeFileSync(configPath, JSON.stringify(clean, null, 2));
  console.log('✓ Fixed dist/server/wrangler.json for Pages V3 compatibility');
} catch (err) {
  console.error('⚠ Could not fix wrangler.json:', err.message);
  // Don't fail the build — let Pages try anyway
}
